779: 	consistentReadFromStorage := resourceVersion == "" && !(consistentListFromCacheEnabled && requestWatchProgressSupported)
780: 	// Watch cache doesn't support continuations, so serve them from etcd.
781: 	hasContinuation := len(pred.Continue) > 0
782: 	// Watch cache only supports ResourceVersionMatchNotOlderThan (default).
783: 	// see https://kubernetes.io/docs/reference/using-api/api-concepts/#semantics-for-get-and-list
784: 	isLegacyExactMatch := opts.Predicate.Limit > 0 && match == "" && len(resourceVersion) > 0 && resourceVersion != "0"
785: 	unsupportedMatch := match != "" && match != metav1.ResourceVersionMatchNotOlderThan || isLegacyExactMatch
786: 
787: 	return consistentReadFromStorage || hasContinuation || unsupportedMatch
