331: // resyncChan returns a channel which will receive something when a resync is
332: // required, and a cleanup function.
333: func (r *Reflector) resyncChan() (<-chan time.Time, func() bool) {
334: 	if r.resyncPeriod == 0 {
335: 		return neverExitWatch, func() bool { return false }
336: 	}
337: 	// The cleanup function is required: imagine the scenario where watches
338: 	// always fail so we end up listing frequently. Then, if we don't
339: 	// manually stop the timer, we could end up with many timers active
340: 	// concurrently.
341: 	t := r.clock.NewTimer(r.resyncPeriod)
342: 	return t.C(), t.Stop
343: }
