969: // GuaranteedUpdate implements storage.Interface.
970: func (c *Cacher) GuaranteedUpdate(
971: 	ctx context.Context, key string, destination runtime.Object, ignoreNotFound bool,
972: 	preconditions *storage.Preconditions, tryUpdate storage.UpdateFunc, _ runtime.Object) error {
973: 	// Ignore the suggestion and try to pass down the current version of the object
974: 	// read from cache.
975: 	if elem, exists, err := c.watchCache.GetByKey(key); err != nil {
976: 		klog.Errorf("GetByKey returned error: %v", err)
977: 	} else if exists {
978: 		// DeepCopy the object since we modify resource version when serializing the
979: 		// current object.
980: 		currObj := elem.(*storeElement).Object.DeepCopyObject()
981: 		return c.storage.GuaranteedUpdate(ctx, key, destination, ignoreNotFound, preconditions, tryUpdate, currObj)
982: 	}
983: 	// If we couldn't get the object, fallback to no-suggestion.
984: 	return c.storage.GuaranteedUpdate(ctx, key, destination, ignoreNotFound, preconditions, tryUpdate, nil)
985: }
